INSERT INTO audio_conversations (id, section_part, title, audio_url, transcript, is_active) VALUES
('a0000001-0001-4000-8000-000000000001', 'A', 'Library Books',   '', E'Man: Have you returned those library books yet?\nWoman: I was going to, but the library closes at five on Fridays.\nMan: Well, you''d better do it first thing Monday, or you''ll get a fine.', TRUE),
('a0000001-0001-4000-8000-000000000002', 'A', 'Chemistry Exam',  '', E'Woman: How did you do on the chemistry midterm?\nMan: I thought I did well, but apparently I mixed up two of the formulas.\nWoman: That''s too bad. Maybe you should form a study group for the final.', TRUE),
('a0000001-0001-4000-8000-000000000003', 'A', 'Campus Shuttle',  '', E'Man: Do you know when the campus shuttle stops running?\nWoman: I think the last one leaves at eleven, but don''t quote me on that.\nMan: I''d better check the schedule online to be sure.', TRUE),
('a0000001-0001-4000-8000-000000000004', 'A', 'Professor Office', '', E'Woman: I need to see Professor Adams about my research paper.\nMan: His office hours are Tuesday and Thursday from two to four.\nWoman: Oh, I have a lab during that time. I''ll have to email him.', TRUE),
('a0000001-0001-4000-8000-000000000005', 'A', 'Cafeteria Food',  '', E'Man: The food in the cafeteria has really improved this semester.\nWoman: I know! They hired a new chef who focuses on healthy options.\nMan: No wonder the salad bar is always so crowded now.', TRUE),
('a0000001-0001-4000-8000-000000000006', 'A', 'Parking Problem',  '', E'Woman: I''ve been driving around for twenty minutes looking for parking.\nMan: You should try the lot behind the science building. It''s usually half empty.\nWoman: Really? I had no idea there was a lot back there.', TRUE),
('a0000001-0001-4000-8000-000000000007', 'A', 'Group Project',   '', E'Man: Have you started working on the group project for sociology?\nWoman: We met yesterday, but we couldn''t agree on a topic.\nMan: Why don''t you let each person present their idea and then vote?', TRUE),
('a0000001-0001-4000-8000-000000000008', 'A', 'Gym Membership',  '', E'Woman: Are you going to renew your gym membership this semester?\nMan: I''m not sure. It''s gotten pretty expensive.\nWoman: They have a student discount if you sign up before September.', TRUE),
('a0000001-0001-4000-8000-000000000009', 'A', 'Weather Change',  '', E'Man: I can''t believe how cold it got overnight.\nWoman: I wish I had checked the forecast. I left my jacket at home.\nMan: You can borrow my extra sweater. It''s in my locker.', TRUE),
('a0000001-0001-4000-8000-000000000010', 'A', 'Essay Deadline',  '', E'Woman: When is the deadline for the history essay?\nMan: It was moved to next Wednesday.\nWoman: Oh good. That gives me a few more days to do research.', TRUE),
('a0000001-0001-4000-8000-000000000011', 'A', 'Financial Aid',   '', E'Man: Have you applied for financial aid yet?\nWoman: I tried, but the online system was down.\nMan: You should go to the financial aid office. They can help you in person.', TRUE),
('a0000001-0001-4000-8000-000000000012', 'A', 'Biology Lab',     '', E'Woman: I missed the biology lab yesterday. Did I miss anything important?\nMan: We dissected a frog. Professor Lee said you can make it up during open lab hours.\nWoman: I''d better schedule that right away before all the slots fill up.', TRUE),
('a0000001-0001-4000-8000-000000000013', 'A', 'Concert Tickets', '', E'Man: Did you get tickets for the jazz concert on Friday?\nWoman: They sold out in less than an hour.\nMan: That''s incredible. Maybe we can try the box office the day of the show.', TRUE),
('a0000001-0001-4000-8000-000000000014', 'A', 'Bookstore',       '', E'Woman: The bookstore is having a sale on textbooks this week.\nMan: Really? I should pick up that calculus book I need.\nWoman: You''d better hurry. The popular ones go fast.', TRUE),
('a0000001-0001-4000-8000-000000000015', 'A', 'Internship',      '', E'Man: I heard you got an internship at the museum.\nWoman: Yes, but it''s unpaid. I''m doing it for the experience.\nMan: That makes sense. It''ll look great on your resume.', TRUE),
('a0000001-0001-4000-8000-000000000016', 'A', 'Roommate Issue',  '', E'Woman: My roommate plays music until midnight every night.\nMan: Have you talked to her about it?\nWoman: I''ve tried, but she says she can''t study without music.', TRUE),
('a0000001-0001-4000-8000-000000000017', 'A', 'Computer Lab',    '', E'Man: Is the computer lab open on weekends?\nWoman: Only on Saturdays from nine to five.\nMan: That should be enough time to finish my programming assignment.', TRUE),
('a0000001-0001-4000-8000-000000000018', 'A', 'Study Abroad',    '', E'Woman: Are you still thinking about studying abroad next year?\nMan: I was, but the cost is more than I expected.\nWoman: Have you looked into the exchange program? It''s much more affordable.', TRUE),
('a0000001-0001-4000-8000-000000000019', 'A', 'Bus Route',       '', E'Man: Which bus goes to the downtown area?\nWoman: You need the number seven. It stops right in front of the student union.\nMan: How often does it run?', TRUE),
('a0000001-0001-4000-8000-000000000020', 'A', 'Art Exhibition',  '', E'Woman: Have you seen the art exhibition in the gallery?\nMan: Not yet. Is it worth going?\nWoman: Definitely. The photography section is particularly impressive.', TRUE),
('a0000001-0001-4000-8000-000000000021', 'A', 'Tutoring Hours',  '', E'Man: I need help with statistics. Do you know any good tutors?\nWoman: The math center offers free tutoring every afternoon.\nMan: Really? I didn''t know that. I''ll check it out tomorrow.', TRUE),
('a0000001-0001-4000-8000-000000000022', 'A', 'Lecture Notes',   '', E'Woman: Could I borrow your notes from Monday''s lecture?\nMan: Sure, but my handwriting is pretty messy.\nWoman: That''s fine. Anything is better than having nothing at all.', TRUE),
('a0000001-0001-4000-8000-000000000023', 'A', 'Registration',    '', E'Man: Have you registered for classes next semester?\nWoman: Not yet. I can''t decide between art history and philosophy.\nMan: Why not take both? They''re at different times.', TRUE),
('a0000001-0001-4000-8000-000000000024', 'A', 'New Professor',   '', E'Woman: What do you think of the new psychology professor?\nMan: She''s excellent. Her lectures are much more engaging than the previous one.\nWoman: I wish I had signed up for her section.', TRUE),
('a0000001-0001-4000-8000-000000000025', 'A', 'Lab Equipment',   '', E'Man: I can''t find the microscope I reserved for my experiment.\nWoman: Someone may have moved it. Check with the lab assistant.\nMan: Good idea. She keeps track of all the equipment.', TRUE),
('a0000001-0001-4000-8000-000000000026', 'A', 'Semester Break',  '', E'Woman: Are you going home for the semester break?\nMan: I was planning to, but I picked up some extra shifts at work.\nWoman: That''s understandable. You can always visit during the longer break.', TRUE),
('a0000001-0001-4000-8000-000000000027', 'A', 'Presentation',    '', E'Man: I''m really nervous about my presentation tomorrow.\nWoman: You should practice in front of a mirror. That''s what I do.\nMan: That''s a good tip. I''ll try that tonight.', TRUE),
('a0000001-0001-4000-8000-000000000028', 'A', 'Swimming Pool',   '', E'Woman: Did you know the university pool is open for free swim in the evenings?\nMan: I didn''t. What time does it close?\nWoman: Nine o''clock on weeknights, but it''s open until ten on Fridays.', TRUE),
('a0000001-0001-4000-8000-000000000029', 'A', 'Newspaper Article','', E'Man: Did you read that article in the campus newspaper about budget cuts?\nWoman: Yes, it said the music department might lose funding.\nMan: That would be terrible. They have one of the best programs in the state.', TRUE),
('a0000001-0001-4000-8000-000000000030', 'A', 'Lunch Plans',     '', E'Woman: Do you want to grab lunch after class?\nMan: I would, but I have to meet my advisor at noon.\nWoman: How about one o''clock then? I''ll wait for you at the cafe.', TRUE);
INSERT INTO questions (id, section, part, question_text, option_a, option_b, option_c, option_d, correct_answer, explanation, difficulty, topic_tags, conversation_group_id, question_order_in_group, is_active) VALUES
('d1000001-0001-4000-8000-000000000001', 1, 'A', 'What does the man suggest the woman do?', 'Return the books today', 'Return the books on Monday', 'Pay the fine immediately', 'Call the library', 'B', 'The man says "you''d better do it first thing Monday" since the library is closed on Friday evenings.', 2, ARRAY['suggestion','campus_life'], 'a0000001-0001-4000-8000-000000000001', 1, TRUE),
('d1000001-0001-4000-8000-000000000002', 1, 'A', 'What happened to the man on the chemistry exam?', 'He did not study enough', 'He confused two formulas', 'He failed the test', 'He arrived late', 'B', 'The man says "apparently I mixed up two of the formulas."', 2, ARRAY['detail','academic'], 'a0000001-0001-4000-8000-000000000002', 1, TRUE),
('d1000001-0001-4000-8000-000000000003', 1, 'A', 'What will the man probably do next?', 'Take the shuttle', 'Ask another student', 'Check the schedule online', 'Walk home', 'C', 'The man says "I''d better check the schedule online to be sure."', 2, ARRAY['inference','campus_life'], 'a0000001-0001-4000-8000-000000000003', 1, TRUE),
('d1000001-0001-4000-8000-000000000004', 1, 'A', 'What is the woman''s problem?', 'She cannot find Professor Adams', 'Her office hours conflict with her schedule', 'She does not have his email', 'Her paper is late', 'B', 'The woman says she has a lab during his office hours, so she''ll have to email him instead.', 2, ARRAY['inference','academic'], 'a0000001-0001-4000-8000-000000000004', 1, TRUE),
('d1000001-0001-4000-8000-000000000005', 1, 'A', 'Why is the salad bar crowded?', 'The prices were lowered', 'A new chef provides healthy options', 'It is the only option available', 'Students get free salad', 'B', 'The woman explains they hired a new chef who focuses on healthy options.', 2, ARRAY['cause_effect','campus_life'], 'a0000001-0001-4000-8000-000000000005', 1, TRUE),
('d1000001-0001-4000-8000-000000000006', 1, 'A', 'What does the man suggest?', 'Parking in front of the building', 'Taking the bus instead', 'Trying the lot behind the science building', 'Arriving earlier', 'C', 'The man suggests trying the lot behind the science building.', 2, ARRAY['suggestion','campus_life'], 'a0000001-0001-4000-8000-000000000006', 1, TRUE),
('d1000001-0001-4000-8000-000000000007', 1, 'A', 'What does the man recommend for the group project?', 'Work individually', 'Let each person present an idea and vote', 'Ask the professor to assign a topic', 'Choose the easiest topic', 'B', 'The man says "Why don''t you let each person present their idea and then vote?"', 2, ARRAY['suggestion','academic'], 'a0000001-0001-4000-8000-000000000007', 1, TRUE),
('d1000001-0001-4000-8000-000000000008', 1, 'A', 'What does the woman tell the man about the gym?', 'It is free for students', 'There is a student discount for early sign-ups', 'It will close next month', 'The equipment is outdated', 'B', 'The woman mentions a student discount if he signs up before September.', 2, ARRAY['detail','campus_life'], 'a0000001-0001-4000-8000-000000000008', 1, TRUE),
('d1000001-0001-4000-8000-000000000009', 1, 'A', 'What does the man offer to do?', 'Drive the woman home', 'Lend her his sweater', 'Check the weather forecast', 'Buy her a new jacket', 'B', 'The man says "You can borrow my extra sweater."', 2, ARRAY['detail','campus_life'], 'a0000001-0001-4000-8000-000000000009', 1, TRUE),
('d1000001-0001-4000-8000-000000000010', 1, 'A', 'How does the woman feel about the changed deadline?', 'Frustrated', 'Relieved', 'Indifferent', 'Confused', 'B', 'The woman says "Oh good. That gives me a few more days to do research," indicating relief.', 2, ARRAY['inference','emotion'], 'a0000001-0001-4000-8000-000000000010', 1, TRUE),
('d1000001-0001-4000-8000-000000000011', 1, 'A', 'What does the man suggest?', 'Try the website again later', 'Visit the financial aid office in person', 'Call the technical support', 'Ask a friend for help', 'B', 'The man says to go to the financial aid office because they can help in person.', 2, ARRAY['suggestion','campus_life'], 'a0000001-0001-4000-8000-000000000011', 1, TRUE),
('d1000001-0001-4000-8000-000000000012', 1, 'A', 'What does the woman need to do?', 'Retake the entire course', 'Schedule a make-up lab session', 'Write an extra report', 'Apologize to Professor Lee', 'B', 'The man mentions she can make it up during open lab hours, so she needs to schedule a make-up session.', 2, ARRAY['inference','academic'], 'a0000001-0001-4000-8000-000000000012', 1, TRUE),
('d1000001-0001-4000-8000-000000000013', 1, 'A', 'What does the man suggest about the concert?', 'Buy tickets online', 'Try the box office on the day of the show', 'Go to a different concert', 'Ask a friend for tickets', 'B', 'The man suggests trying the box office the day of the show.', 2, ARRAY['suggestion','campus_life'], 'a0000001-0001-4000-8000-000000000013', 1, TRUE),
('d1000001-0001-4000-8000-000000000014', 1, 'A', 'What does the woman warn the man about?', 'The bookstore might be closed', 'Popular books sell out quickly', 'The sale ends tomorrow', 'The books are damaged', 'B', 'The woman says "You''d better hurry. The popular ones go fast."', 2, ARRAY['detail','campus_life'], 'a0000001-0001-4000-8000-000000000014', 1, TRUE),
('d1000001-0001-4000-8000-000000000015', 1, 'A', 'Why did the woman accept an unpaid internship?', 'She was required to', 'For the practical experience', 'She could not find a paid one', 'It was only part-time', 'B', 'The woman says "I''m doing it for the experience."', 2, ARRAY['detail','academic'], 'a0000001-0001-4000-8000-000000000015', 1, TRUE),
('d1000001-0001-4000-8000-000000000016', 1, 'A', 'What is the woman''s problem?', 'Her roommate eats her food', 'Her roommate plays music late at night', 'Her roommate never cleans', 'Her roommate has too many visitors', 'B', 'The woman says her roommate plays music until midnight every night.', 1, ARRAY['detail','campus_life'], 'a0000001-0001-4000-8000-000000000016', 1, TRUE),
('d1000001-0001-4000-8000-000000000017', 1, 'A', 'When is the computer lab open on weekends?', 'All day Sunday', 'Saturday nine to five', 'Saturday and Sunday nine to nine', 'It is closed on weekends', 'B', 'The woman says it''s only open on Saturdays from nine to five.', 2, ARRAY['detail','campus_life'], 'a0000001-0001-4000-8000-000000000017', 1, TRUE),
('d1000001-0001-4000-8000-000000000018', 1, 'A', 'What does the woman suggest about studying abroad?', 'Applying for a scholarship', 'Looking into the exchange program', 'Waiting until graduate school', 'Saving money first', 'B', 'The woman suggests the exchange program because it''s more affordable.', 2, ARRAY['suggestion','academic'], 'a0000001-0001-4000-8000-000000000018', 1, TRUE),
('d1000001-0001-4000-8000-000000000019', 1, 'A', 'What does the man want to know?', 'The fare for the bus', 'Which bus goes downtown', 'Where to buy a bus pass', 'The bus driver''s name', 'B', 'The man asks "Which bus goes to the downtown area?"', 1, ARRAY['detail','campus_life'], 'a0000001-0001-4000-8000-000000000019', 1, TRUE),
('d1000001-0001-4000-8000-000000000020', 1, 'A', 'What does the woman say about the exhibition?', 'It is boring', 'It is not worth seeing', 'The photography section is impressive', 'It closes next week', 'C', 'The woman says "The photography section is particularly impressive."', 2, ARRAY['detail','campus_life'], 'a0000001-0001-4000-8000-000000000020', 1, TRUE),
('d1000001-0001-4000-8000-000000000021', 1, 'A', 'What will the man probably do?', 'Hire a private tutor', 'Visit the math center tomorrow', 'Drop the statistics course', 'Ask the woman for help', 'B', 'The man says "I''ll check it out tomorrow" after learning about the free tutoring.', 2, ARRAY['inference','academic'], 'a0000001-0001-4000-8000-000000000021', 1, TRUE),
('d1000001-0001-4000-8000-000000000022', 1, 'A', 'Why is the woman willing to use messy notes?', 'She prefers handwritten notes', 'Having something is better than nothing', 'She can read any handwriting', 'She plans to rewrite them', 'B', 'The woman says "Anything is better than having nothing at all."', 2, ARRAY['inference','academic'], 'a0000001-0001-4000-8000-000000000022', 1, TRUE),
('d1000001-0001-4000-8000-000000000023', 1, 'A', 'What does the man suggest?', 'Drop one of the courses', 'Take both courses', 'Ask the advisor', 'Wait until next year', 'B', 'The man says "Why not take both? They''re at different times."', 2, ARRAY['suggestion','academic'], 'a0000001-0001-4000-8000-000000000023', 1, TRUE),
('d1000001-0001-4000-8000-000000000024', 1, 'A', 'How does the woman feel about the new professor?', 'She admires her and regrets not taking the class', 'She thinks her lectures are boring', 'She already has the professor', 'She is planning to switch sections', 'A', 'The woman says "I wish I had signed up for her section," showing admiration and regret.', 3, ARRAY['inference','emotion'], 'a0000001-0001-4000-8000-000000000024', 1, TRUE),
('d1000001-0001-4000-8000-000000000025', 1, 'A', 'What does the woman suggest about the microscope?', 'Buy a new one', 'Check with the lab assistant', 'Look in the storage room', 'Ask the professor', 'B', 'The woman says "Check with the lab assistant."', 1, ARRAY['suggestion','academic'], 'a0000001-0001-4000-8000-000000000025', 1, TRUE),
('d1000001-0001-4000-8000-000000000026', 1, 'A', 'Why is the man not going home for the break?', 'He has too much homework', 'He picked up extra work shifts', 'He doesn''t have transportation', 'His family is visiting him', 'B', 'The man says he "picked up some extra shifts at work."', 2, ARRAY['detail','campus_life'], 'a0000001-0001-4000-8000-000000000026', 1, TRUE),
('d1000001-0001-4000-8000-000000000027', 1, 'A', 'What is the woman''s advice?', 'Cancel the presentation', 'Practice in front of a mirror', 'Ask a classmate to present instead', 'Read the notes aloud', 'B', 'The woman advises practicing in front of a mirror.', 1, ARRAY['suggestion','academic'], 'a0000001-0001-4000-8000-000000000027', 1, TRUE),
('d1000001-0001-4000-8000-000000000028', 1, 'A', 'What time does the pool close on Fridays?', 'Eight o''clock', 'Nine o''clock', 'Ten o''clock', 'Eleven o''clock', 'C', 'The woman says "it''s open until ten on Fridays."', 2, ARRAY['detail','campus_life'], 'a0000001-0001-4000-8000-000000000028', 1, TRUE),
('d1000001-0001-4000-8000-000000000029', 1, 'A', 'What might happen to the music department?', 'It will receive more funding', 'It might lose funding due to budget cuts', 'It will merge with another department', 'It is expanding its programs', 'B', 'The woman says the article mentioned the music department might lose funding.', 2, ARRAY['detail','campus_life'], 'a0000001-0001-4000-8000-000000000029', 1, TRUE),
('d1000001-0001-4000-8000-000000000030', 1, 'A', 'What does the woman propose?', 'Eating lunch at noon', 'Meeting at the cafe at one o''clock', 'Canceling lunch plans', 'Going to a restaurant off campus', 'B', 'The woman suggests meeting at one o''clock at the cafe.', 1, ARRAY['suggestion','campus_life'], 'a0000001-0001-4000-8000-000000000030', 1, TRUE);
INSERT INTO audio_conversations (id, section_part, title, audio_url, transcript, is_active) VALUES
('a0000001-0002-4000-8000-000000000001', 'B', 'Academic Advising Session', '',
INSERT INTO questions (id, section, part, question_text, option_a, option_b, option_c, option_d, correct_answer, explanation, difficulty, topic_tags, conversation_group_id, question_order_in_group, is_active) VALUES
('d1000002-0001-4000-8000-000000000001', 1, 'B', 'Why is the student meeting with the advisor?', 'To drop a course', 'To discuss her schedule for next semester', 'To complain about a professor', 'To apply for graduation', 'B', 'The woman says she''s there to discuss her course schedule for next semester.', 2, ARRAY['main_idea','academic_advising'], 'a0000001-0002-4000-8000-000000000001', 1, TRUE),
('d1000002-0001-4000-8000-000000000002', 1, 'B', 'What does the advisor recommend?', 'Dropping her job', 'Taking fewer credits next semester', 'Avoiding organic chemistry', 'Changing her major', 'B', 'The advisor recommends reducing to fourteen credits if she takes organic chemistry.', 2, ARRAY['detail','academic_advising'], 'a0000001-0002-4000-8000-000000000001', 2, TRUE),
('d1000002-0001-4000-8000-000000000003', 1, 'B', 'How can the student avoid delaying graduation?', 'By taking more credits this semester', 'By taking a summer course', 'By testing out of a requirement', 'By attending evening classes', 'B', 'The advisor suggests taking a summer course to make up the credits.', 3, ARRAY['detail','academic_advising'], 'a0000001-0002-4000-8000-000000000001', 3, TRUE),
('d1000002-0001-4000-8000-000000000004', 1, 'B', 'What does the advisor say about the chemistry study group?', 'It is required for the course', 'Students who join tend to do better', 'It meets every day', 'It is only for graduate students', 'B', 'The advisor says students who participate in the study group tend to perform significantly better.', 2, ARRAY['detail','academic_advising'], 'a0000001-0002-4000-8000-000000000001', 4, TRUE),
('d1000002-0001-4000-8000-000000000005', 1, 'B', 'What is the man''s problem?', 'His room is too expensive', 'He was assigned a triple room instead of a double', 'His roommate is too noisy', 'He missed the housing deadline', 'B', 'The man says he was assigned to a triple room but requested a double.', 2, ARRAY['main_idea','campus_life'], 'a0000001-0002-4000-8000-000000000002', 1, TRUE),
('d1000002-0001-4000-8000-000000000006', 1, 'B', 'Why couldn''t the man get a double room?', 'He applied too late', 'There were more applicants than rooms available', 'Double rooms were under renovation', 'He didn''t qualify', 'B', 'The woman says there were more applicants than double rooms available.', 2, ARRAY['detail','campus_life'], 'a0000001-0002-4000-8000-000000000002', 2, TRUE),
('d1000002-0001-4000-8000-000000000007', 1, 'B', 'What does the man decide to do?', 'Move off campus', 'Stay on the waiting list', 'Share with only one roommate', 'File a formal complaint', 'B', 'The man says "Please put me on the waiting list" and that he''d rather stay on campus.', 2, ARRAY['detail','campus_life'], 'a0000001-0002-4000-8000-000000000002', 3, TRUE),
('d1000002-0001-4000-8000-000000000008', 1, 'B', 'What additional help does the woman offer?', 'A room discount', 'A meeting with roommates and an RA', 'A private room temporarily', 'A refund for the inconvenience', 'B', 'The woman offers to arrange a meeting with his roommates and an RA to discuss room guidelines.', 3, ARRAY['detail','campus_life'], 'a0000001-0002-4000-8000-000000000002', 4, TRUE);
INSERT INTO audio_conversations (id, section_part, title, audio_url, transcript, is_active) VALUES
('a0000001-0003-4000-8000-000000000001', 'C', 'The Water Cycle', '',
INSERT INTO questions (id, section, part, question_text, option_a, option_b, option_c, option_d, correct_answer, explanation, difficulty, topic_tags, conversation_group_id, question_order_in_group, is_active) VALUES
('d1000003-0001-4000-8000-000000000001', 1, 'C', 'What is the lecture mainly about?', 'Types of clouds', 'How the water cycle works', 'Ocean pollution', 'Weather forecasting methods', 'B', 'The lecture is primarily about the water cycle and its stages.', 2, ARRAY['main_idea','science'], 'a0000001-0003-4000-8000-000000000001', 1, TRUE),
('d1000003-0001-4000-8000-000000000002', 1, 'C', 'According to the professor, what are condensation nuclei?', 'Large raindrops', 'Tiny particles like dust and pollen', 'Types of clouds', 'Water molecules', 'B', 'The professor says condensation nuclei are tiny particles such as dust, pollen, or pollution.', 2, ARRAY['detail','science'], 'a0000001-0003-4000-8000-000000000001', 2, TRUE),
('d1000003-0001-4000-8000-000000000003', 1, 'C', 'What percentage of precipitation falls into the oceans?', 'Fifty percent', 'Sixty-five percent', 'Seventy-five percent', 'Ninety percent', 'C', 'The professor states that about seventy-five percent of precipitation falls into the oceans.', 3, ARRAY['detail','science'], 'a0000001-0003-4000-8000-000000000001', 3, TRUE),
('d1000003-0001-4000-8000-000000000004', 1, 'C', 'What is transpiration?', 'Water evaporating from the ocean', 'Plants releasing water into the atmosphere', 'Rain falling on mountains', 'Water flowing into rivers', 'B', 'The professor defines transpiration as plants releasing water back into the atmosphere through their roots.', 2, ARRAY['vocabulary','science'], 'a0000001-0003-4000-8000-000000000001', 4, TRUE),
('d1000003-0001-4000-8000-000000000005', 1, 'C', 'What is the main point of the lecture?', 'How books were made in monasteries', 'The impact of Gutenberg''s printing press', 'The invention of paper in China', 'Modern printing technology', 'B', 'The lecture focuses on the development and transformative impact of Gutenberg''s printing press.', 2, ARRAY['main_idea','history'], 'a0000001-0003-4000-8000-000000000002', 1, TRUE),
('d1000003-0001-4000-8000-000000000006', 1, 'C', 'According to the professor, what did Gutenberg do?', 'Invented printing for the first time', 'Combined existing technologies into a practical system', 'Discovered oil-based ink', 'Taught monks to print books', 'B', 'The professor says Gutenberg combined several existing technologies into a practical, efficient system.', 3, ARRAY['detail','history'], 'a0000001-0003-4000-8000-000000000002', 2, TRUE),
('d1000003-0001-4000-8000-000000000007', 1, 'C', 'What effect did the printing press have?', 'It made books more expensive', 'It reduced literacy rates', 'It made knowledge accessible to more people', 'It replaced handwriting entirely', 'C', 'The professor says it made knowledge accessible to a much wider audience and literacy rates rose.', 2, ARRAY['detail','history'], 'a0000001-0003-4000-8000-000000000002', 3, TRUE),
('d1000003-0001-4000-8000-000000000008', 1, 'C', 'What does the professor mean by "democratized knowledge"?', 'Knowledge became controlled by government', 'Information was no longer restricted to elites', 'Everyone had to attend school', 'Libraries became free to the public', 'B', 'The professor explains that information was no longer controlled exclusively by religious and political elites.', 3, ARRAY['inference','history'], 'a0000001-0003-4000-8000-000000000002', 4, TRUE),
('d1000003-0001-4000-8000-000000000009', 1, 'C', 'Which animal makes the longest migration?', 'The monarch butterfly', 'The sea turtle', 'The Arctic tern', 'The salmon', 'C', 'The professor says the Arctic tern makes the longest migration of any animal.', 2, ARRAY['detail','biology'], 'a0000001-0003-4000-8000-000000000003', 1, TRUE),
('d1000003-0001-4000-8000-000000000010', 1, 'C', 'How do sea turtles navigate?', 'By following ocean currents', 'By detecting the Earth''s magnetic field', 'By following other animals', 'By using their sense of smell', 'B', 'The professor says sea turtles can detect the Earth''s magnetic field and use it as an internal compass.', 3, ARRAY['detail','biology'], 'a0000001-0003-4000-8000-000000000003', 2, TRUE),
('d1000003-0001-4000-8000-000000000011', 1, 'C', 'What is remarkable about monarch butterfly migration?', 'They fly faster than birds', 'No single butterfly completes the round trip', 'They only migrate at night', 'They travel in groups of millions', 'B', 'The professor says no single butterfly makes the complete round trip; it takes three to four generations.', 3, ARRAY['detail','biology'], 'a0000001-0003-4000-8000-000000000003', 3, TRUE),
('d1000003-0001-4000-8000-000000000012', 1, 'C', 'What helps monarch butterflies navigate?', 'A visual memory of landmarks', 'A protein in their antennae sensitive to magnetic fields', 'The scent of specific flowers', 'Sound waves from other butterflies', 'B', 'The professor mentions a special protein in monarch butterfly antennae sensitive to the Earth''s magnetic field.', 3, ARRAY['detail','biology'], 'a0000001-0003-4000-8000-000000000003', 4, TRUE);
